function parseLogLine(line: string): { method: string; path: string; status: number } | null {
  const parts = line.trim().split(' ');
  if (parts.length < 3) return null;
  return {
    method: parts[0],
    path: parts[1],
    status: parseInt(parts[2], 10),
  };
}

function generateSummary(requests: { method: string; path: string; status: number }[]): string {
  const total = requests.length;
  const success = filterBy(requests, r => r.status >= 200 && r.status < 300).length;
  const errors = filterBy(requests, r => r.status >= 400).length;
  const timestamp = new Date().toISOString();
  return `${timestamp},${total},${success},${errors}`;
}

