async function handleDnsQuery(domain: string): Promise<string> {
  // 1. Check Cache
  const cachedRecords = await queryDatabase(`SELECT * FROM dns_cache WHERE domain = '${domain}'`);

  if (cachedRecords.length > 0) {
    const record = cachedRecords[0];
    if (record.expiry > Date.now()) {
      return record.ip;
    }
  }

  // 2. Lookup Authoritative Nameserver (using DoH API as proxy)
  const response = await fetchFromApi(`https://dns.google/resolve?name=${domain}&type=A`);
  const answer = response.Answer[0];
  const ip = answer.data;
  const ttl = answer.TTL;

  // 3. Cache Result with TTL
  const expiry = Date.now() + (ttl * 1000);
  await writeToDatabase('dns_cache', { domain, ip, expiry });

  // 4. Return Resolved IP
  return ip;
}
