function formatBriefing(weather: any, events: any[], traffic: any): string {
  const weatherSummary = `It is currently ${weather.temp}°F and ${weather.condition}.`;
  const eventSummary = events.length > 0
    ? `You have ${events.length} events today: ${events.map((e: any) => e.title).join(', ')}.`
    : 'You have no events scheduled for today.';
  const trafficSummary = `Current traffic conditions: ${traffic.status}.`;

