async function analyzeBrandSentiment(brand: string) {
  // 1. Fetch data from all sources simultaneously
  const [twitterData, redditData, hnData] = await Promise.all([
    fetchFromApi(`https://api.twitter.com/search?q=${brand}`),
    fetchFromApi(`https://api.reddit.com/search?q=${brand}`),
    fetchFromApi(`https://hacker-news.firebaseio.com/v0/search?q=${brand}`)
  ]);

  // 2. Normalize data and add source attribution
  const twitterMentions = mapItems(twitterData.statuses || [], (t: any) => ({ text: t.text, source: 'Twitter' }));
  const redditMentions = mapItems(redditData.data?.children || [], (p: any) => ({ text: p.data.body, source: 'Reddit' }));
  const hnMentions = mapItems(hnData.hits || [], (h: any) => ({ text: h.title || h.text, source: 'HackerNews' }));

  const allMentions = [...twitterMentions, ...redditMentions, ...hnMentions];

  // 3. Classify sentiment for each mention
  const classifiedMentions = await Promise.all(
    mapItems(allMentions, async (mention) => {
      const sentiment = await llmClassify(mention.text, ['positive', 'neutral', 'negative']);
      return { ...mention, sentiment };
    })
  );

  // 4. Aggregate into a unified sentiment score
  const totalScore = aggregate(
    classifiedMentions,
    (acc, item) => {
      if (item.sentiment === 'positive') return acc + 1;
      if (item.sentiment === 'negative') return acc - 1;
      return acc;
    },
    0
  );

  // 5. Group by source for attribution
  const attribution = groupBy(classifiedMentions, 'source');

  return {
    brand,
    totalScore,
    attribution
  };
}

async function main() {
  const report = await analyzeBrandSentiment('TypeScript');
  await writeFile('./sentiment-report.json', JSON.stringify(report, null, 2));
