```typescript
interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
}

interface CartEvent {
  type: 'add' | 'remove';
  itemId: string;
  name: string;
  price: number;
  quantity: number;
}

interface CartSummary {
  items: CartItem[];
  subtotal: number;
  tax: number;
  shipping: number;
  total: number;
}

const TAX_RATE = 0.08;
const SHIPPING_COST = 9.99;
const FREE_SHIPPING_THRESHOLD = 100;

async function main() {
  const eventStream = connectWebSocket('wss://api.example.com/cart-events');
  let cartState: Record<string, CartItem> = {};

  for await (const event of eventStream) {
    cartState = processEvent(cartState, event);
    const summary = calculateTotals(cartState);
    await writeToDatabase('cart_state', summary);
  }
}

function processEvent(currentCart: Record<string, CartItem>, event: CartEvent): Record<string, CartItem> {
  const { itemId, type, quantity, name, price } = event;
  const existing = currentCart[itemId];

  if (type === 'add') {
    if (existing) {
      return {
        ...currentCart,
        [itemId]: { ...existing, quantity: existing.quantity + quantity }
      };
    }
    return {
      ...currentCart,
      [itemId]: { id: itemId, name, price, quantity }
    };
  }

  if (type === 'remove' && existing) {
    const newQuantity = Math.max(0, existing.quantity - quantity);
    if (newQuantity === 0) {
      const { [itemId]: _, ...rest } = currentCart;
      return rest;
    }
    return {
      ...currentCart,
      [itemId]: { ...existing, quantity: newQuantity }
    };
  }

  return currentCart;
}

function calculateTotals(cart: Record<string, CartItem>): CartSummary {
  const items = Object.values(cart);
  const subtotal = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const tax = subtotal * TAX_RATE;
  const shipping = subtotal > 0 && subtotal < FREE_SHIPPING_THRESHOLD ? SHIPPING_COST : 0;
  const total = subtotal + tax + shipping;

  return { items, subtotal, tax, shipping, total };
}
