function updateLeaderboard(event: ScoreEvent): boolean {
  const previousTop10 = JSON.stringify(leaderboard.slice(0, 10));

  const existingIndex = leaderboard.findIndex(p => p.playerId === event.playerId);

  if (existingIndex >= 0) {
    if (event.score > leaderboard[existingIndex].score) {
      leaderboard[existingIndex].score = event.score;
    }
  } else {
    leaderboard.push({ playerId: event.playerId, score: event.score });
  }

  leaderboard.sort((a, b) => b.score - a.score);
  leaderboard = leaderboard.slice(0, 10);

  const newTop10 = JSON.stringify(leaderboard);
  return previousTop10 !== newTop10;
}

function formatLeaderboard(entries: LeaderboardEntry[]): string {
  const rankings = mapItems(entries, (entry, index) => 
    `${index + 1}. ${entry.playerId}: ${entry.score}`
  );
  return "Updated Leaderboard:\n" + rankings.join('\n');
}
