async function getPriceWithRetry(apiUrl: string, cachePath: string) {
  const maxRetries = 3;
  let attempt = 0;

  while (attempt <= maxRetries) {
    try {
      const response = await fetchFromApi(apiUrl);
      await logToAudit({ status: 'success', attempt: attempt + 1, url: apiUrl });
      return response.price;
    } catch (error) {
      await logToAudit({ status: 'failed', attempt: attempt + 1, error: String(error), url: apiUrl });

      if (attempt < maxRetries) {
        const backoffMs = Math.pow(2, attempt) * 1000;
        await new Promise(resolve => setTimeout(resolve, backoffMs));
      }
      attempt++;
    }
  }

  const cachedContent = await readFile(cachePath);
  const cachedData = JSON.parse(cachedContent);
  return cachedData.price;
}
