// State
let circuitState: 'CLOSED' | 'OPEN' | 'HALF_OPEN' = 'CLOSED';
let requestHistory: { timestamp: number; success: boolean }[] = [];
let openedAt: number = 0;

const CONFIG = {
  WINDOW_MS: 30000,
  TIMEOUT_MS: 10000,
  FAILURE_THRESHOLD: 0.5
};

async function processPayment(paymentDetails: any) {
  const now = Date.now();

  // Check Circuit State
  if (circuitState === 'OPEN') {
    if (now - openedAt > CONFIG.TIMEOUT_MS) {
      circuitState = 'HALF_OPEN';
    } else {
      return { status: 'degraded', message: 'Circuit breaker is OPEN' };
    }
  }

  // Execute Request
  let result: any;
  let success = false;

  try {
    result = await fetchFromApi('https://api.payment-gateway.com/charge', {
      method: 'POST',
      body: JSON.stringify(paymentDetails)
    });
    // Assuming standard HTTP status check
    success = result.ok !== false; 
  } catch (error) {
    success = false;
  }

  // Handle State Transitions
  if (circuitState === 'HALF_OPEN') {
    if (success) {
      circuitState = 'CLOSED';
      requestHistory = []; // Reset history on successful recovery
    } else {
      circuitState = 'OPEN';
      openedAt = now;
      return { status: 'degraded', message: 'Probe failed, circuit OPEN' };
    }
  } else {
    // CLOSED state
    updateHistory(success);
    if (checkFailureRate()) {
      circuitState = 'OPEN';
      openedAt = now;
    }
  }

  return result;
}

function updateHistory(success: boolean) {
  const now = Date.now();
  requestHistory.push({ timestamp: now, success });
  // Maintain sliding window of 30 seconds
  requestHistory = requestHistory.filter(entry => now - entry.timestamp <= CONFIG.WINDOW_MS);
}

function checkFailureRate(): boolean {
  if (requestHistory.length === 0) return false;
  const failureCount = requestHistory.filter(entry => !entry.success).length;
  return (failureCount / requestHistory.length) > CONFIG.FAILURE_THRESHOLD;
}
